--
-- Table structure for table `alum_atrasos`
--

DROP TABLE IF EXISTS `alum_atrasos`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `alum_atrasos` (
  `id` int NOT NULL AUTO_INCREMENT,
  `matricula_id` int NOT NULL,
  `semestre` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1 = primer semestre, 2 = segundo semestre',
  `fecha` date NOT NULL,
  `hora_llegada` time NOT NULL,
  `justificado` tinyint(1) NOT NULL DEFAULT '0',
  `observacion` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `registrado_por` int DEFAULT NULL COMMENT 'user_id del funcionario que registra',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_atraso_matricula` (`matricula_id`),
  KEY `idx_atraso_fecha` (`fecha`),
  CONSTRAINT `fk_atraso_matricula` FOREIGN KEY (`matricula_id`) REFERENCES `matriculas2` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1077 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

