  `descripcion` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `sem1_inicio` date DEFAULT NULL COMMENT 'Inicio 1° Semestre',
  `sem1_fin` date DEFAULT NULL COMMENT 'Fin 1° Semestre',
  `sem2_inicio` date DEFAULT NULL COMMENT 'Inicio 2° Semestre',
  `sem2_fin` date DEFAULT NULL COMMENT 'Fin 2° Semestre',
  PRIMARY KEY (`id`),
  UNIQUE KEY `anio` (`anio`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
