DROP TABLE IF EXISTS `anotaciones2`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `anotaciones2` (
  `id` int NOT NULL AUTO_INCREMENT,
  `alumno_id` int NOT NULL,
  `matricula_id` int NOT NULL,
  `asignatura_id` int NOT NULL,
  `contenido` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `tipo` enum('Registro','Positiva','Leve','Grave','Gravísima') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `semestre` tinyint NOT NULL COMMENT '1 o 2',
  `fecha_anotacion` date NOT NULL DEFAULT (curdate()),
  `notificado_apoderado` enum('Si','No') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'No',
  `accion_realizada` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_anotacion_alumno` (`alumno_id`),
  KEY `idx_anotacion_matricula` (`matricula_id`),
  KEY `idx_anotacion_asignatura` (`asignatura_id`),
  CONSTRAINT `anotaciones2_ibfk_1` FOREIGN KEY (`alumno_id`) REFERENCES `alumnos2` (`id`) ON DELETE CASCADE,
  CONSTRAINT `anotaciones2_ibfk_2` FOREIGN KEY (`matricula_id`) REFERENCES `matriculas2` (`id`) ON DELETE CASCADE,
  CONSTRAINT `anotaciones2_ibfk_3` FOREIGN KEY (`asignatura_id`) REFERENCES `asignaturas2` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=192 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
